/**
* Assembles the complete ToolRegistration for the Portneuf Portal.
*
* This is the main integration point that connects all Lancelot subsystems
* (views, tree, filters, status bar, lifecycle) into a single registration object.
*/ var lancelotRegistration = {
	id: "lancelot",
	name: "Lancelot",
	subtitle: "Semiconductor Inspection",
	version: "0.1.0",
	icon: Hexagon,
	basePath: "/lancelot",
	navItems: lancelotViews.map((v) => v.navItem),
	views: lancelotViews,
	defaultViewPath: "wafer-map",
	treeComponent: lazy(() => import("./LancelotFileTree-hn14Cgu_.js")),
	globalFilters: lazy(() => import("./LancelotFilters-D4l5qLcA.js")),
	statusBarSlots: [{
		id: "lancelot-file-info",
		position: "left",
		priority: 10,
		component: lazy(() => import("./StatusBarSlots-cLN6H0rc.js").then((m) => ({ default: m.FileInfoSlot }))),
		source: "tool"
	}, {
		id: "lancelot-defect-count",
		position: "left",
		priority: 20,
		component: lazy(() => import("./StatusBarSlots-cLN6H0rc.js").then((m) => ({ default: m.DefectCountSlot }))),
		source: "tool"
	}],
	panelConstraints: {
		tree: {
			minWidth: 200,
			maxWidth: 400,
			defaultWidth: 280
		},
		sidebar: {
			minWidth: 280,
			maxWidth: 400,
			defaultWidth: 320
		}
	},
	lifecycle: {
		onActivate: () => {
			setPortalMode(true);
			initializeRegistry();
		},
		onDeactivate: () => {
			return true;
		}
	}
};
